    </div>
  </div>

  <div *ngIf="loading" class="loading-wrap"><div class="spinner"></div></div>

  <div *ngIf="!loading && pending.length === 0" class="card empty-state" style="padding:80px">
    <div class="empty-icon" style="color:var(--success)">✓</div>
    <div class="empty-title">All clear!</div>
    <div class="empty-desc">No pending approvals at this time</div>
  </div>

  <div *ngIf="!loading && pending.length > 0" class="card" style="padding:0">
    <table class="data-table">
      <thead>
        <tr><th>Person</th><th>Role</th><th>Department</th><th>Team</th><th>Experience</th><th>Skills</th><th>Actions</th></tr>
      </thead>
      <tbody>
        <tr *ngFor="let u of pending">
          <td>
            <div style="display:flex;align-items:center;gap:10px">
              <div class="avatar">{{ u.firstName[0] }}{{ u.lastName[0] }}</div>
              <div>
                <div style="font-weight:600">{{ u.firstName }} {{ u.lastName }}</div>
                <div style="font-size:12px;color:var(--text-muted)">{{ u.email }}</div>
              </div>
            </div>
          </td>
          <td><span class="badge badge-blue">{{ formatRole(u.role) }}</span></td>
          <td>{{ u.department?.name || '—' }}</td>
          <td>{{ u.team?.name || '—' }}</td>
          <td>{{ u.experienceYears || 0 }} yrs</td>
          <td>
            <div style="display:flex;flex-wrap:wrap;gap:4px;max-width:200px">
              <span *ngFor="let s of u.skills" class="skill-chip" style="font-size:11px">{{ s.name }}</span>
              <span *ngIf="!u.skills?.length" style="color:var(--text-muted)">—</span>
            </div>
          </td>
          <td>
            <div style="display:flex;gap:6px">
              <button class="btn btn-success btn-sm" (click)="confirmApprove(u)">✓ Approve</button>
              <button class="btn btn-danger btn-sm" (click)="confirmReject(u)">✕ Reject</button>
            </div>
          </td>
        </tr>
      </tbody>
    </table>
  </div>

  <div *ngIf="showApproveConfirm" class="modal-overlay fade-in">
    <div class="modal">
      <div class="modal-header">
        <div class="modal-title">Confirm Approval</div>
        <button class="close-btn" (click)="showApproveConfirm = false">✕</button>
      </div>
      <div class="modal-body" style="padding:20px; text-align:center;">
        <div style="font-size:40px;margin-bottom:12px">✅</div>
        <div style="font-size:16px;font-weight:600;margin-bottom:8px">Approve {{ selectedUser?.firstName }} {{ selectedUser?.lastName }}?</div>
        <div style="font-size:13px;color:var(--text-muted)">This user will be granted access to the system.</div>
        <div style="display:flex;gap:10px;margin-top:24px">
          <button class="btn btn-secondary" style="flex:1;justify-content:center" (click)="showApproveConfirm = false">Cancel</button>
          <button class="btn btn-success" style="flex:1;justify-content:center" (click)="approve()" [disabled]="processing === selectedUser?.id">
            {{ processing === selectedUser?.id ? 'Approving...' : 'Yes, Approve' }}
          </button>
        </div>
      </div>
    </div>
  </div>

  <div *ngIf="showRejectConfirm" class="modal-overlay fade-in">
    <div class="modal">
      <div class="modal-header">
        <div class="modal-title">Confirm Rejection</div>
        <button class="close-btn" (click)="showRejectConfirm = false">✕</button>
      </div>
      <div class="modal-body" style="padding:20px; text-align:center;">
        <div style="font-size:40px;margin-bottom:12px;color:var(--danger)">⚠️</div>
        <div style="font-size:16px;font-weight:600;color:var(--danger);margin-bottom:8px">Reject {{ selectedUser?.firstName }} {{ selectedUser?.lastName }}?</div>
        <div style="font-size:13px;color:var(--text-muted)">This will deny access to the system for this user.</div>
        <div style="display:flex;gap:10px;margin-top:24px">
          <button class="btn btn-secondary" style="flex:1;justify-content:center" (click)="showRejectConfirm = false">Cancel</button>
          <button class="btn btn-danger" style="flex:1;justify-content:center" (click)="reject()" [disabled]="processing === selectedUser?.id">
            {{ processing === selectedUser?.id ? 'Rejecting...' : 'Yes, Reject' }}
          </button>
        </div>
      </div>
    </div>
  </div>
</div>
